function calculate({ numberOfParticipants, programCostPerParticipant, programDurationYears, successRate, baselineUnemploymentRate, postProgramUnemploymentReduction, baselineAverageIncome, postProgramIncomeIncreasePercent, healthCareCostReductionPerPerson, civicEngagementValuePerPerson }) {

  // Ensure inputs are valid numbers and handle non-positive values where appropriate
  numberOfParticipants = Math.max(0, numberOfParticipants || 0);
  programCostPerParticipant = Math.max(0, programCostPerParticipant || 0);
  programDurationYears = Math.max(0, programDurationYears || 0);
  successRate = Math.min(100, Math.max(0, successRate || 0)); // Cap success rate between 0 and 100
  baselineUnemploymentRate = Math.min(100, Math.max(0, baselineUnemploymentRate || 0)); // Cap unemployment rate
  postProgramUnemploymentReduction = Math.max(0, postProgramUnemploymentReduction || 0);
  baselineAverageIncome = Math.max(0, baselineAverageIncome || 0);
  postProgramIncomeIncreasePercent = Math.max(0, postProgramIncomeIncreasePercent || 0);
  healthCareCostReductionPerPerson = Math.max(0, healthCareCostReductionPerPerson || 0);
  civicEngagementValuePerPerson = Math.max(0, civicEngagementValuePerPerson || 0);

  // 1. Calculate Total Program Cost
  const totalProgramCost = numberOfParticipants * programCostPerParticipant * programDurationYears;

  // 2. Calculate Successful Participants
  const successfulParticipants = numberOfParticipants * (successRate / 100);

  // 3. Calculate Economic Gain from New Employment
  // This is the number of successful participants who move from unemployed to employed.
  const unemploymentRateReductionForSuccessful = postProgramUnemploymentReduction / 100;
  const numNewlyEmployed = successfulParticipants * unemploymentRateReductionForSuccessful;
  const economicGainFromEmployment = numNewlyEmployed * baselineAverageIncome;

  // 4. Calculate Income Increase for Employed Successful Participants
  // This applies to all successful participants who are employed after the program (both newly employed and those already employed).
  const currentBaselineUnemploymentRate = baselineUnemploymentRate / 100;
  const finalUnemploymentRateForSuccessful = Math.max(0, currentBaselineUnemploymentRate - unemploymentRateReductionForSuccessful);
  const numEmployedSuccessful = successfulParticipants * (1 - finalUnemploymentRateForSuccessful);
  const incomeIncreaseForEmployed = numEmployedSuccessful * baselineAverageIncome * (postProgramIncomeIncreasePercent / 100);

  // 5. Calculate Total Healthcare Savings
  const totalHealthcareSavings = successfulParticipants * healthCareCostReductionPerPerson;

  // 6. Calculate Total Social Benefits
  const totalSocialBenefits = successfulParticipants * civicEngagementValuePerPerson;

  // 7. Calculate Net Economic Impact
  const totalBenefits = economicGainFromEmployment + incomeIncreaseForEmployed + totalHealthcareSavings + totalSocialBenefits;
  const netEconomicImpact = totalBenefits - totalProgramCost;

  // 8. Calculate Return on Investment (ROI)
  const roi = (totalProgramCost > 0) ? (netEconomicImpact / totalProgramCost) * 100 : 0;

  return {
    totalProgramCost,
    economicGainFromEmployment,
    incomeIncreaseForEmployed,
    totalHealthcareSavings,
    totalSocialBenefits,
    netEconomicImpact,
    roi
  };
}
